				Movement.collectTarget(target);
				if pathFolder then
					pathFolder:ClearAllChildren();
				end
				safeWait(0.2);
			else
				if (State.Status ~= LUAOBFUSACTOR_DECRYPT_STR_0("\151\25\131\235", "\191\192\88\202")) then
