					local h, r = Utils.getHum(), Utils.getRoot();
					if (h and r) then
						h:MoveTo(r.Position);
					end
					if pathFolder then
						pathFolder:ClearAllChildren();
					end
				end
				safeWait(1);
			end
		else
			safeWait(0.5);
		end
	end
end
